// ═══════════ CALAMITIES (plague, floods, famine) ═══════════
export const calamities = [
  {year:1246, type:'plague', label:'Plague epidemic',         detail:'An early plague outbreak struck the Pomeranian coast, devastating the sparse population of the emerging trading settlement.'},
  {year:1310, type:'fire',  label:'Teutonic fire', detail:'During the Teutonic Knights\' consolidation of power following the 1308 Gdańsk Massacre, parts of the city were torched. The wooden buildings of the old settlement burned; only stone ecclesiastical structures survived. The fire cleared ground for the Knights\' ambitious rebuilding programme.'},
  {year:1349, type:'plague', label:'Black Death reaches Gdańsk', detail:'The Black Death (bubonic plague) reached Gdańsk via maritime trade routes in 1349–1350. Estimated 30–40% of the population perished. The epidemic devastated the labour force and temporarily halted church construction.'},
  {year:1358, type:'plague', label:'Plague recurrence',       detail:'A second wave of plague struck, further depleting the population that had barely recovered from the Black Death.'},
  {year:1424, type:'fire',  label:'Great fire — Old Suburb', detail:'A devastating fire swept through the Old Suburb (Stare Przedmieście), destroying large sections of the quarter including the Church of Ss. Peter & Paul. The reconstruction took years; the 1427 plague entry references it as \'three years after the 1424 fire\'.'},
  {year:1427, type:'plague', label:'Plague outbreak',         detail:'A severe plague outbreak struck three years after the 1424 fire, compounding the devastation in the Old Suburb and further delaying reconstruction of Ss. Peter & Paul.'},
  {year:1464, type:'plague', label:'Plague during Thirteen Years\' War', detail:'Plague struck during the Thirteen Years\' War, adding disease to the miseries of military conflict. The combination of war and epidemic severely reduced the city\'s population.'},
  {year:1520, type:'plague', label:'Plague epidemic',         detail:'A major plague outbreak coincided with the Polish-Teutonic War (1519–21), killing thousands. The epidemic may have contributed to the social unrest that erupted in the 1525 Protestant tumults.'},
  {year:1540, type:'flood', label:'Great Vistula flood', detail:'An exceptional Vistula flood inundated the Lower Town and Granary Island, destroying stockpiled grain and forcing emergency repairs to the riverbank embankments. The flood highlighted the city\'s chronic vulnerability to Vistula overflow.'},
  {year:1556, type:'fire',  label:'Great town fire', detail:'A major fire broke out in the Main Town, destroying several blocks of timber-framed buildings along the waterfront. The disaster accelerated the transition to full brick construction in the inner city and prompted new fire-prevention ordinances.'},
  {year:1564, type:'plague', label:'Plague — 8,000 dead',     detail:'A devastating plague killed approximately 8,000 people in Gdańsk — roughly 20% of the population. This was one of the worst single epidemics in the city\'s history.'},
  {year:1602, type:'plague', label:'Plague epidemic',         detail:'Another severe plague outbreak, part of the recurring cycle of epidemics that struck Baltic trading cities through infected maritime trade.'},
  {year:1603, type:'flood', label:'Vistula flood — granaries damaged', detail:'A major spring flood breached the embankments east of the city, flooding dozens of granaries on Granary Island and destroying tens of thousands of łaszts of stored grain.'},
  {year:1624, type:'plague', label:'Plague — peak mortality', detail:'An extremely severe plague outbreak struck Gdańsk at the height of its commercial prosperity (~70,000 population), killing an estimated 10,000–15,000 people. Ship quarantine measures proved inadequate against the scale of infection.'},
  {year:1653, type:'plague', label:'Plague epidemic',         detail:'Plague struck again, further reducing the population that had already declined from the combined effects of war (the Deluge) and previous epidemics.'},
  {year:1698, type:'flood', label:'Post-war flood', detail:'Following the devastation of the Swedish wars (1655–1660), a severe Vistula flood struck the weakened city. The embankment system, neglected during wartime, failed at several points, flooding the Lower Town and Old Suburb.'},
  {year:1709, type:'plague', label:'Great Northern Plague',   detail:'The Great Northern Plague, spreading from the Great Northern War battlefields, devastated Gdańsk in 1709–1710. An estimated 24,000–32,000 people died — roughly half the city\'s population. This was the deadliest epidemic in Gdańsk\'s entire history and permanently reduced the city to a shadow of its golden age.'},
  {year:1736, type:'flood', label:'Catastrophic Vistula flood', detail:'The worst flood in decades breached the Vistula embankments on a broad front, inundating the Lower Town and Old Suburb to chest height. Hundreds of buildings collapsed. The disaster is documented in city council records as \'the great water\'.'},
  {year:1813, type:'fire',  label:'Siege fire', detail:'During the Napoleonic siege of Danzig (1807–1814), the French garrison and subsequent Prussian siege operations caused widespread fires in the Lower Town and outer suburbs. The Granary Island granaries and workshops were heavily damaged.'},
  {year:1829, type:'flood', label:'Major inundation', detail:'A powerful spring flood overflowed the Vistula embankments, causing widespread damage to the Lower Town and suburbs. Prussian authorities launched a major review of flood defences.'},
  {year:1831, type:'plague', label:'Cholera epidemic',        detail:'The first cholera pandemic reached Gdańsk in 1831, carried along trade routes from Russia. Hundreds died before sanitary measures contained the outbreak.'},
  {year:1866, type:'plague', label:'Cholera returns',         detail:'A second major cholera epidemic struck Gdańsk, prompting the Prussian administration to invest in modern sewerage and water treatment systems.'},
  {year:1888, type:'flood', label:'Last great flood', detail:'The last catastrophic Vistula flood before modern flood-control works were completed. The 1888 inundation prompted the Prussian government to fund the Vistula cut (Przekop Wisły), which redirected the river directly to the sea — ending the perennial flood threat to Gdańsk.'},
  {year:1918, type:'plague', label:'Spanish Flu',             detail:'The 1918–1919 influenza pandemic struck Gdańsk as it did all of Europe. Thousands fell ill; mortality compounded war exhaustion and food shortages. The epidemic hit as political upheaval was reshaping the city\'s future at Versailles.'},
  {year:1945, type:'fire',  label:'WWII — City burns', detail:'Soviet artillery and fire during the Battle of Danzig (March 1945) burned 90–95% of the historic centre to the shell. St. Mary\'s, St. Catherine\'s, St. Nicholas\' and every major church became gutted ruins. Polish craftsmen spent the following decades reconstructing the city stone by stone from historical records.'},
];

// ═══════════ POLITICAL EVENTS ═══════════
export const politicalEvents = [
  {year:1227,  label:'Pomeranian dukes rule Gdańsk',          color:'var(--ink-lt)',    isSiege:false, detail:'Gdańsk served as the political center of Pomerelia under the Samboride dynasty. Duke Świętopełk II promoted the city\'s development by granting privileges to merchants, founding a merchant settlement under Lübeck law, and inviting the Dominicans, who established St. Nicholas\' Church on 22 January 1227.'},
  {year:1282,  label:'Treaty of Kępno — Polish succession',   color:'var(--amber)',      isSiege:false, detail:'On 15 February 1282, Duke Mestwin II, last of the Samboride line, signed the Treaty of Kępno — a donatio inter vivos transferring suzerainty over Pomerelia to Przemysł II, Duke of Greater Poland. Mestwin retained de facto control until his death in 1294, after which Przemysł took direct possession, reuniting Pomerelia with the Polish lands.'},
  {year:1308,  label:'Teutonic Seizure of Gdańsk',             color:'#8b3a2a',           isSiege:true,  detail:'On 13 November 1308, the Teutonic Knights — called to reinforce the Polish garrison against a Brandenburg siege — turned on the defenders and townspeople, killing an estimated 1,000 inhabitants in what became known as the Gdańsk Massacre (rzeź Gdańska). The Order seized the town and castle, beginning 146 years of Teutonic rule that fundamentally reshaped the city\'s governance, trade, and ecclesiastical organisation.'},
  {year:1343,  label:'Treaty of Kalisz',                       color:'var(--amber)',      isSiege:false, detail:'On 8 July 1343, Casimir III the Great renounced Polish claims to Pomerelia and Chełmno Land in exchange for regaining Kuyavia and Dobrzyń Land. The treaty formalised Teutonic control over Gdańsk that had begun with the 1308 takeover, and ushered in a 66-year period of peace between the two powers.'},
  {year:1361,  label:'Hanseatic League membership confirmed',  color:'#2a5c6e',           isSiege:false, detail:'Gdańsk became a full member of the Hanseatic League, joining the most powerful commercial network in northern Europe. Coordinated through Lübeck\'s Hansetag, the League gave Gdańsk access to shared trade law, diplomatic protection, and privileged markets from London to Novgorod.'},
  {year:1411,  label:'First Peace of Toruń',                   color:'var(--amber)',      isSiege:false, detail:'Ended the Polish–Lithuanian–Teutonic war following the Battle of Grunwald. Although militarily decisive, territorial changes were limited, preserving Order control over Gdańsk and Royal Prussia for another four decades.'},
  {year:1440,  label:'Prussian Confederation formed',          color:'var(--amber)',      isSiege:false, detail:'On 21 February 1440, 53 nobles, clergy, and 19 cities — including Gdańsk — formed the Prussian Confederation (Związek Pruski) at Kwidzyn to oppose Teutonic taxation and arbitrary governance. This alliance would trigger the Thirteen Years\' War 14 years later.'},
  {year:1454,  label:'Castle demolished — war begins',         color:'#8b3a2a',           isSiege:false, detail:'In February 1454, after the Prussian Confederation submitted to the Polish Crown, an anti-Teutonic uprising broke out in Gdańsk. On 11 February the citizens captured and demolished the hated Teutonic castle brick by brick, using the rubble for city fortifications. The Thirteen Years\' War had begun.'},
  {year:1466,  label:'Second Peace of Toruń — Polish Crown',   color:'var(--amber)',      isSiege:false, detail:'The Second Peace of Toruń (October 19, 1466) ended the Thirteen Years\' War. Royal Prussia was incorporated into the Polish Crown; Gdańsk retained wide autonomy and commercial privileges — its own laws, currency, army, and the right to conduct foreign policy.'},
  {year:1505,  label:'Nihil Novi — szlachta ascendancy',       color:'var(--amber)',      isSiege:false, detail:'The Nihil Novi act, adopted at the Sejm in Radom (1505), forbade the king from enacting laws without noble consent, inaugurating Poland\'s "Nobles\' Democracy." While Gdańsk\'s exceptional autonomy was preserved, the broader shift toward szlachta dominance gradually reshaped Crown–city relations.'},
  {year:1526,  label:'Sigismund I restores order — Catholic concessions', color:'#c0463a', isSiege:false, detail:'In April 1526 King Sigismund I the Old entered Gdańsk with 8,000 troops to suppress the Protestant tumults. Fourteen ringleaders were beheaded in front of the Artus Court and the pre-Reformation Catholic magistrate was reinstated. However, the king made pragmatic concessions: Lutheran preaching was tolerated in some outer parishes and expelled friars were not forced back into contested buildings, effectively acknowledging the irreversible shift in popular religious allegiance while formally maintaining Catholic supremacy.'},
  {year:1569,  label:'Union of Lublin',                        color:'var(--amber)',      isSiege:false, detail:'The Union of Lublin (1 July 1569) created the Polish-Lithuanian Commonwealth. Gdańsk merchants controlled roughly 80% of the Commonwealth\'s inland grain trade, shipping it via the Vistula to Baltic markets. The grain trade peaked in the following decades, making Gdańsk one of the wealthiest cities in Europe.'},
  {year:1612,  label:'Counter-Reformation pressure mounts',    color:'#4a6a3a',           isSiege:false, detail:'King Sigismund III Vasa\'s policy of appointing only Catholics to offices increasingly pressured Gdańsk\'s Protestant establishment. By the 1610s, Calvinist access to civic positions was being curtailed, marking the start of Counter-Reformation encroachment on the city\'s multi-confessional balance.'},
  {year:1618,  label:"Thirty Years' War begins",               color:'#705030',           isSiege:false, detail:"The outbreak of the Thirty Years' War (1618–1648) began a period of general European conflict that severely disrupted the Baltic trade networks on which Gdańsk's prosperity depended. Gdańsk's Hanseatic-era commercial network, already weakened by Dutch and English competition and Lübeck's declining coordinating influence, enters structural decline."},
  {year:1651,  label:'Calvinist worship restricted to two churches', color:'#4a6a3a',    isSiege:false, detail:'A crucial agreement mediated by the Polish Crown with Dutch States-General involvement limited Calvinist worship to just two churches: St. Elizabeth\'s (Old Town) and Ss. Peter & Paul (Main Town/Old Suburb). This dramatic contraction reflected Calvinist political decline despite their continued commercial importance.'},
  {year:1772,  label:'First Partition of Poland',              color:'var(--amber)',      isSiege:false, detail:'The First Partition of Poland (1772) saw Prussia annex almost all of Royal Prussia, but Gdańsk and Toruń were excluded — largely because Russia\'s Catherine II feared a Prussian-controlled port would enable Frederick II to build a Baltic navy. Gdańsk became an exclave separated from the rump Commonwealth, its trade strangled by Prussian tariffs on all sides.'},
  {year:1793,  label:'Prussian annexation — autonomy ends',    color:'var(--amber)',      isSiege:false, detail:'The Second Partition of Poland (January 1793) finally placed Gdańsk under Prussian rule. The population largely opposed annexation — the mayor resigned in protest. Over 300 years of autonomous governance under the Polish Crown ended as Prussia systematically dismantled the city\'s unique privileges.'},
  {year:1815,  label:'Congress of Vienna — Prussian rule confirmed', color:'var(--amber)', isSiege:false, detail:'The Congress of Vienna (1815) confirmed Prussian sovereignty over Gdańsk after the Napoleonic interlude. The city entered a new phase as a provincial Prussian city, losing its former autonomy but gaining access to the growing German industrial economy.'},
  {year:1871,  label:'German Empire — industrialisation',      color:'var(--amber)',      isSiege:false, detail:'German unification under Bismarck (1871) incorporated Gdańsk into the German Empire. The city industrialised rapidly, its shipyards expanding and population growing. The controversial 1890–1900 church "restorations" replaced authentic medieval surfaces with machine-made clinker bricks.'},
  {year:1918,  label:'End of WWI — armistice',                 color:'var(--amber)',      isSiege:false, detail:'The armistice of November 11, 1918, ended the First World War and dissolved the German Empire. For Gdańsk (Danzig), the post-war settlement at Versailles would separate the city from Germany and establish the Free City of Danzig under League of Nations mandate.'},
  {year:1920,  label:'Free City of Danzig established',        color:'var(--amber)',      isSiege:false, detail:'On 15 November 1920, per the Treaty of Versailles, the Free City of Danzig was formally established under League of Nations protection. About 90% of the population was German, yet Poland held rights over foreign affairs, customs, railways, and the post. This compromise satisfied no one and became a flashpoint of interwar tensions.'},
  {year:1939,  label:'Nazi annexation — Free City ends',       color:'#8b3a2a',           isSiege:false, detail:'On September 1, 1939, Nazi Germany annexed the Free City of Danzig and launched the invasion of Poland — the opening shots of World War II were fired at the Westerplatte peninsula. The 20-year experiment of the Free City ended instantly.'},
  {year:1945.5,label:'Post-war demographic rupture',           color:'#8b3a2a',           isSiege:false, detail:'After the Soviet assault destroyed the city and the German population fled or was expelled, Polish resettlement transformed the city completely. Gdańsk was reconstituted as a Polish city for the first time since 1793.'},
  {year:1980,  label:'Solidarity movement born',               color:'var(--amber)',      isSiege:false, detail:'In August 1980, strikes at the Gdańsk Shipyard led by Lech Wałęsa created the Solidarity trade union — the first independent labour union in the Soviet bloc. The movement would eventually topple communist rule across Eastern Europe.'},
  {year:1989,  label:'Fall of communism — democracy restored', color:'var(--amber)',      isSiege:false, detail:'The Round Table Agreements of 1989 ended communist rule in Poland. For Gdańsk\'s churches, this meant full religious freedom, removal of bureaucratic obstruction, and completion of long-delayed reconstruction projects.'},
  {year:2004,  label:'Poland joins the European Union',        color:'#2a5c6e',           isSiege:false, detail:'Poland\'s accession to the European Union on May 1, 2004, opened new opportunities for Gdańsk as an EU port and logistics hub. The city\'s historic port was upgraded with EU structural funds.'},
];

// ═══════════ RELIGIOUS EVENTS ═══════════
export const religiousEvents = [
  {year:1227,  label:'Dominican mission — St. Nicholas founded',  color:'#c0463a',  detail:'On 22 January 1227, Duke Świętopełk II granted the newly arrived Dominican friars a church that became St. Nicholas\', the first major religious institution in Gdańsk. Impact on churches: St. Nicholas\' became the permanent Dominican anchor, surviving all subsequent political upheavals.'},
  {year:1415,  label:'Council of Constance',                      color:'#5a3a6e',  detail:'The Council of Constance (1414–1418) condemned Jan Hus and attempted to heal the Western Schism. Its decrees on heresy influenced how Gdańsk\'s clergy and Teutonic authorities later responded to pre-Reformation dissent. Impact on churches: reinforced Catholic orthodoxy across Teutonic-controlled parishes.'},
  {year:1523,  label:'First Lutheran sermons in Gdańsk',          color:'#3a7a9e',  detail:'Protestant preachers began delivering Lutheran sermons in private homes and outer parishes, building popular support among merchants and craftsmen. Impact on churches: seeds of confessional change that would transform every parish within 35 years.'},
  {year:1525,  label:'Danzig Tumult — monastic upheaval',         color:'#8b3a2a',  detail:'On 22 January 1525, Protestant riots erupted in Gdańsk: mobs attacked Franciscan, Dominican, and Carmelite monasteries, looted property, vandalised sacred images, and expelled monks. In April 1526, King Sigismund I entered the city with 8,000 troops, had 14 ringleaders beheaded in front of the Artus Court, and restored the Catholic magistrate — but the damage to monastic communities proved irreversible. Impact on churches: multiple monastic churches permanently lost their religious orders.'},
  {year:1525.5,label:'Teutonic Order secularised — Prussian Homage', color:'#3a7a9e', detail:'Grand Master Albert of Brandenburg-Ansbach announced his conversion to Lutheranism on 9 April 1525, dissolved the Teutonic Order in Prussia, and accepted the territory as a hereditary secular duchy under Polish suzerainty — the Duchy of Prussia. This removed the last institutional obstacle to Protestantism in the region. Impact on churches: emboldened Gdańsk\'s growing Lutheran movement and weakened Catholic oversight.'},
  {year:1557,  label:'Religious Freedom Privilege',                color:'#3a7a9e',  detail:'King Sigismund II Augustus issued the Privilegium Sigismundi Augusti, granting Gdańsk the right to practise the Lutheran faith. On 31 October 1557 — the 40th anniversary of Luther\'s Ninety-Five Theses — communion under both kinds was administered throughout Gdańsk\'s churches, marking the definitive Lutheran takeover. Impact on churches: St. Mary\'s and most parishes officially became Lutheran; only Dominican St. Nicholas\' and a handful of monastic houses remained Catholic.'},
  {year:1573,  label:'Warsaw Confederation — religious tolerance', color:'var(--amber)', detail:'The Warsaw Confederation of 28 January 1573 guaranteed religious tolerance throughout the Polish-Lithuanian Commonwealth — one of the first and most comprehensive state guarantees of religious freedom in European history, now on UNESCO\'s Memory of the World register. Impact on churches: protected Gdańsk\'s multi-confessional character, ensuring Catholic, Lutheran, and Calvinist worship could coexist.'},
  {year:1612,  label:'Counter-Reformation — Calvinist restrictions', color:'#4a6a3a', detail:'King Sigismund III Vasa barred Calvinists from civic offices and began pushing Counter-Reformation policies. Impact on churches: Calvinist congregations began losing access to churches, foreshadowing the 1651 restriction to only two buildings.'},
  {year:1651,  label:'Calvinist worship confined to two churches', color:'#4a6a3a',  detail:'An agreement mediated by the Polish Crown with Dutch States-General involvement limited Calvinist worship to St. Elizabeth\'s and Ss. Peter & Paul. Impact on churches: dramatic contraction of Reformed worship space, several former Calvinist churches reverted to Lutheran use.'},
  {year:1678,  label:'Royal Chapel — Catholic foothold built',     color:'#c0463a',  detail:'King John III Sobieski commissioned the Royal Chapel (Kaplica Królewska, completed 1681) adjacent to Lutheran St. Mary\'s, providing Catholics with a dignified worship space in the heart of the Main Town. Impact on churches: the only new Catholic construction in Protestant-dominated Gdańsk for over a century.'},
  {year:1945.5,label:'All churches reconsecrated Catholic',        color:'#c0463a',  detail:'After the Soviet assault and German expulsion, all surviving Protestant churches were reconsecrated as Roman Catholic by incoming Polish clergy. Impact on churches: the entire denominational landscape was transformed in months — a change more sweeping than the Reformation itself.'},
  {year:1980,  label:'St. Bridget\'s — the Solidarity church',     color:'#c0463a',  detail:'Father Henryk Jankowski celebrated masses for striking shipyard workers at St. Bridget\'s Church, making it the spiritual centre of the Solidarity movement. Impact on churches: St. Bridget\'s became a symbol of civic resistance and Catholic resilience under communist rule.'},
];

// ═══════════ WARS & CONFLICTS ═══════════
export const wars = [
  {start:1308, end:1309,  label:'Teutonic takeover of Gdańsk',        color:'#8b3a2a', detail:`<div class="war-also-known">Also known as: <strong>Rzeź Gdańska</strong> (Polish, "Gdańsk Massacre") · <em>Einnahme Danzigs durch den Deutschen Orden</em> (German)</div><div style="margin-bottom:10px;">The Teutonic Knights, originally invited by Duke Władysław Łokietek to repel a Brandenburgian attack, turned on the city they were meant to defend. In the night of 12–13 November 1308 they breached Gdańsk's defences, massacred the garrison, and occupied the town — beginning 146 years of Teutonic rule.</div><div class="war-combatants"><div class="war-side" style="background:rgba(60,60,80,0.12);border-left:3px solid rgba(60,60,80,0.5);"><div class="war-side-label">Teutonic Order (victor)</div><div class="war-side-name">Heinrich von Plötzke<br>Günther von Schwarzburg</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Bogusza (Polish governor)<br>Gdańsk garrison</div></div></div><ul class="war-facts"><li><strong>1308</strong> — Brandenburg forces threaten Gdańsk; Łokietek requests Teutonic Knights' help.</li><li><strong>12–13 Nov 1308</strong> — Teutonic Knights breach city defences at night; massacre ensues. Modern historians estimate 60–150 killed (older claims of 10,000 are rejected).</li><li><strong>13 Sep 1309</strong> — Treaty of Soldin: the Order purchases Brandenburg's claimed rights over Gdańsk for 10,000 silver marks, legalising its hold.</li><li><strong>1308–1454</strong> — Gdańsk remains under Teutonic Order control for 146 years.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Teutonic Seizure</div><div class="war-outcome-text">Treaty of Soldin (1309). The Teutonic Order secured Gdańsk and Pomerelia, cutting Poland off from the Baltic Sea for over a century and a half.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The massacre and seizure transformed Gdańsk from a Polish-ruled port into the administrative centre of Teutonic Pomerelia. The Knights rebuilt the city on a grid plan and imposed Culm Law, leaving an urban legacy visible to this day. The event is remembered in Poland as a foundational trauma motivating the eventual Thirteen Years' War of 1454–1466.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Teutonic_takeover_of_Danzig_(Gda%C5%84sk)" target="_blank" rel="noopener">📖 Wikipedia — Teutonic takeover of Danzig (Gdańsk)</a>`},
  {start:1409, end:1411,  label:'Polish-Teutonic War (Grunwald)',      color:'#8b3a2a', detail:`<div class="war-also-known">Also known as: <strong>Wielka Wojna</strong> (Polish, "Great War") · <em>Großer Krieg</em> (German) · <em>Battle of Tannenberg / Žalgiris</em></div><div style="margin-bottom:10px;">The climactic medieval confrontation between the Polish-Lithuanian Commonwealth and the Teutonic Order. The Battle of Grunwald on 15 July 1410 was one of the largest battles in European history — Grand Master Ulrich von Jungingen and most of the Order's senior leadership were killed. Teutonic military prestige was shattered, though Gdańsk remained under the Order.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland-Lithuania (victor)</div><div class="war-side-name">King Władysław II Jagiełło<br>Grand Duke Vytautas</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Grand Master Ulrich von Jungingen<br>Teutonic Order</div></div></div><ul class="war-facts"><li><strong>1409</strong> — Samogitian uprising; Poland supports rebels; Teutonic Order declares war.</li><li><strong>15 Jul 1410</strong> — Battle of Grunwald: Ulrich von Jungingen killed; Teutonic leadership annihilated.</li><li><strong>1410</strong> — Failed Polish siege of Marienburg/Malbork; heroic defence by Heinrich von Plauen saves the Order's capital.</li><li><strong>1 Feb 1411</strong> — First Peace of Thorn: Order pays massive war indemnity; returns Samogitia.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Polish-Lithuanian Victory</div><div class="war-outcome-text">First Peace of Thorn (1411). The Teutonic Order survived but was crippled. Heavy indemnities and lost prestige began the slow collapse that culminated in the Thirteen Years' War.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk remained under Teutonic control after the war, but the Order's new punishing taxes to fund the indemnity provoked bitter resentment among the city's merchants. This economic pressure directly fuelled the formation of the Prussian Confederation in 1440 and the eventual 1454 uprising that returned Gdańsk to Poland.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Polish%E2%80%93Lithuanian%E2%80%93Teutonic_War" target="_blank" rel="noopener">📖 Wikipedia — Polish-Lithuanian-Teutonic War</a>`},
  {start:1414, end:1414,  label:'Hunger War',                          color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Wojna głodowa</strong> (Polish) · <em>Hungerkrieg</em> (German, "Hunger War")</div><div style="margin-bottom:10px;">A brief but gruelling conflict following Grunwald. Poland sought to exploit the Order's weakness, but the Teutonic Order responded with scorched-earth tactics — burning crops and refusing open battle — forcing both sides into exhausted stalemate. The campaign's name reflects the resulting famine conditions.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Participants</div><div class="war-side-name">King Władysław II Jagiełło<br>Grand Duke Vytautas</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Participants</div><div class="war-side-name">Grand Master Heinrich von Plauen<br>Teutonic Order</div></div></div><ul class="war-facts"><li><strong>Summer 1414</strong> — Polish-Lithuanian armies invade Prussia; Order burns crops and retreats, refusing battle.</li><li><strong>Oct 1414</strong> — Truce of Brodnica (Strasburg); dispute referred to Council of Constance.</li><li><strong>1414–1418</strong> — Council of Constance convenes but ends without resolving the Polish-Teutonic dispute.</li><li><strong>1422</strong> — Treaty of Melno finally settles the Lithuanian-Teutonic border.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Inconclusive</div><div class="war-outcome-text">Truce of Brodnica (1414). Neither side gained territory. The core dispute over Pomerelia and Samogitia remained unresolved for decades.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk's merchants bore compounded tax burdens — the 1411 First Peace of Thorn indemnity plus new levies to fund this war. The mounting financial pressure deepened popular hostility toward Teutonic rule and accelerated the formation of the Prussian Confederation that eventually triggered the 1454 uprising.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Hunger_War" target="_blank" rel="noopener">📖 Wikipedia — Hunger War</a>`},
  {start:1433, end:1433,  label:'Hussite raid on Pomerania',           color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Spanilá jízda</strong> (Czech, "Beautiful Ride") · <em>Hussitenfahrt nach Danzig</em> (German)</div><div style="margin-bottom:10px;">Czech Hussite warriors — veterans of a decade of crushing crusades against them — raided Pomerania and Royal Prussia in alliance with Poland, reaching the Baltic Sea near Gdańsk. The city itself was never attacked, but Oliwa Abbey was burned, a key Vistula crossing captured, and the Teutonic Order's inability to defend its own territory was humiliatingly exposed.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Hussites + Polish backing</div><div class="war-side-name">Jan Čapek of Sány<br>(Sirotci Hussites)<br>Contracted by Jagiełło</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Teutonic Order</div><div class="war-side-name">(no effective response;<br>garrisoned in castles)</div></div></div><ul class="war-facts"><li><strong>1432</strong> — King Jagiełło contracts 7,000 Hussite troops (Sirotci faction) as mercenaries at Pabianice to pressure the Teutonic Order.</li><li><strong>29 Aug 1433</strong> — Hussites capture Tczew (Dirschau) on the Vistula — a key trade crossing near Gdańsk.</li><li><strong>1 Sep 1433</strong> — Hussite army camps near Gdańsk; the fortified city is too strong to assault, but the surrounding countryside is ravaged.</li><li><strong>Early Sep 1433</strong> — Forces burn <strong>Oliwa Abbey</strong>; the Hussites reach the Baltic Sea and symbolically fill flasks with seawater — completing their "Beautiful Ride to the Sea."</li><li><strong>13 Sep 1433</strong> — Truce of Jasiniec signed; Hussites withdraw after six weeks in the region.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Military demonstration</div><div class="war-outcome-text">Truce of Jasiniec (1433). No territorial changes — but the Order's failure to repel the raiders confirmed its military decline and accelerated the formation of the Prussian Confederation, which triggered the 1454 uprising.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The Hussites camped near Gdańsk for several days without attempting a siege. However, Oliwa Abbey — within the city's sphere — was burned, and Tczew (a vital trade crossing) was captured. The episode confirmed what Gdańsk's merchant class already suspected: the Teutonic Order could no longer fulfil its duty of military protection.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Hussite_expedition_to_the_Baltic" target="_blank" rel="noopener">📖 Wikipedia — Hussite expedition to the Baltic</a>`},
  {start:1454, end:1466,  label:'Thirteen Years\' War',                color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Wojna trzynastoletnia</strong> (Polish) · <em>Dreizehnjähriger Krieg</em> (German) · War of the Cities</div><div style="margin-bottom:10px;">The defining conflict of Gdańsk's history. On 30 March 1454 the city's citizens expelled the Teutonic garrison and invited King Casimir IV Jagiellon to take sovereignty. Twelve years of brutal warfare followed. The city financed the Polish war effort, provided the decisive naval force, and in victory won extraordinary autonomy that would last three centuries.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland + Prussian Confederation (victor)</div><div class="war-side-name">King Casimir IV Jagiellon<br>Gdańsk · Toruń · Elbląg</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Teutonic Order<br>+ Bohemian mercenaries</div></div></div><ul class="war-facts"><li><strong>30 Mar 1454</strong> — Gdańsk expels the Teutonic garrison; Casimir IV issues the Incorporation Act of Prussia.</li><li><strong>1454</strong> — Casimir grants Gdańsk the Great Privilege — its own laws, army, coinage, and foreign affairs.</li><li><strong>18 Sep 1454</strong> — Battle of Chojnice: serious Polish defeat; Order hires Bohemian mercenaries with indemnity payments.</li><li><strong>1457</strong> — Gdańsk funds the purchase of Malbork Castle from unpaid mercenaries; the Order's capital changes hands without a fight.</li><li><strong>15 Sep 1463</strong> — Battle of Zatoka Świeża: Gdańsk-Elbląg fleet destroys 44 Teutonic ships — the decisive naval victory.</li><li><strong>19 Oct 1466</strong> — Second Peace of Toruń signed; Royal Prussia returned to Poland.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Polish-Prussian Victory</div><div class="war-outcome-text">Second Peace of Toruń (19 October 1466). Western Prussia including Gdańsk, Toruń, and Elbląg returned to Poland. The Teutonic Order retained eastern Prussia as a Polish vassal state. Gdańsk's broad autonomy was guaranteed in law.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk was the engine of the Polish war effort — financing the campaign, providing the decisive naval force, and leading the urban uprising. In return the city received the 1457 Great Privilege, which made it the most autonomous city in Europe: effectively a city-state within Poland. The Teutonic castle, demolished brick by brick in 1454, was never rebuilt — its cleared site remains open ground to this day.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Thirteen_Years%27_War_(1454%E2%80%931466)" target="_blank" rel="noopener">📖 Wikipedia — Thirteen Years' War (1454–1466)</a>`},

  // ── War of the Priests (1467–1479) ──────────────────────────
  // Correctly identified separate conflict from the 1519–21 war.
  // Polish: Wojnę popią · German: Pfaffenkrieg
  // Cause: disputed episcopal succession in the Bishopric of Warmia.
  // Source: https://en.wikipedia.org/wiki/Polish%E2%80%93Teutonic_War_(1467%E2%80%931479)
  {start:1467, end:1479,  label:'War of the Priests',                  color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Pfaffenkrieg</strong> (German) · <em>Wojnę popią</em> (Polish)</div><div style="margin-bottom:10px;">A conflict triggered by a disputed episcopal appointment in the Bishopric of Warmia. Pope Paul II installed the Teutonic-backed Nicolaus von Tüngen as bishop without royal consent; Casimir IV refused to recognise him. The Teutonic Order — technically a Polish vassal since 1466 — backed Tüngen, hoping to use the crisis to overturn the <em>Second Peace of Toruń</em> and recover its lost autonomy.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland (victor)</div><div class="war-side-name">Casimir IV Jagiellon<br>Royal Prussian cities</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Teutonic Order<br>Bishop Tüngen<br>+ Hungary (1476–79)</div></div></div><ul class="war-facts"><li><strong>1467</strong> — Pope Paul II appoints Tüngen; Casimir IV withholds recognition.</li><li><strong>1472</strong> — Tüngen enters Warmia under Teutonic escort.</li><li><strong>1476</strong> — Matthias Corvinus of Hungary invades southern Poland as the Order's ally.</li><li><strong>1477</strong> — Grand Master von Richtenberg refuses military aid to his Polish suzerain — a direct breach of his vassal obligations.</li><li><strong>1478</strong> — Polish forces (Jan Biały, Piotr Dunin) besiege Braniewo, occupy Warmia and Pomesanian towns. Tüngen flees to Königsberg.</li><li><strong>Apr 1479</strong> — Corvinus withdraws; Tüngen and Grand Master submit to Casimir IV.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Polish Victory</div><div class="war-outcome-text">Treaty of Piotrków (1479). Both Tüngen and Grand Master von Richtenberg paid homage to Casimir IV. The Order's bid to overturn the Second Peace of Toruń failed; Polish suzerainty was reconfirmed.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The conflict centred on Warmia, not Gdańsk directly. Yet each Polish victory over the Order reinforced Gdańsk's exceptional autonomy within Royal Prussia, shielding the city's commercial privileges from any Teutonic resurgence.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Polish%E2%80%93Teutonic_War_(1467%E2%80%931479)" target="_blank" rel="noopener">📖 Wikipedia — War of the Priests</a>`},

  {start:1469, end:1474,  label:'Anglo-Hanseatic War',                 color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Anglo-Hanseatic Trade War</strong> · The Paul Beneke Affair · "The First Art Heist"</div><div style="margin-bottom:10px;">A commercial conflict between England and the Hanseatic League over mutual trading privileges. The war produced one of the most extraordinary episodes in Gdańsk's history: privateer Paul Beneke's capture of a Flemish galley carrying Hans Memling's <em>Last Judgement</em> triptych — which has never left Gdańsk since.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Hanseatic League</div><div class="war-side-name">Paul Beneke (Gdańsk)<br>Lübeck (lead Hanse city)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Kingdom of England<br>King Edward IV</div></div></div><ul class="war-facts"><li><strong>1468</strong> — England seizes Hanseatic merchant ships; the League retaliates with embargo and privateers.</li><li><strong>1469</strong> — Paul Beneke given command of Gdańsk's warship <em>Peter von Danzig</em>.</li><li><strong>27 Apr 1473</strong> — Beneke intercepts the Burgundian galley <em>St. Matthew</em> in the North Sea; seizes its cargo — including Hans Memling's <em>Last Judgement</em> triptych, commissioned for a Bruges hospital by Florentine banker Angelo Tani.</li><li><strong>1474</strong> — A papal lawsuit demands return of the triptych; Gdańsk refuses; it is placed in the Basilica of the Assumption as high altarpiece.</li><li><strong>1474</strong> — Treaty of Utrecht: English merchants' core privileges restored; Hanseatic trade rights confirmed.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Hanseatic settlement</div><div class="war-outcome-text">Treaty of Utrecht (1474). The Hanseatic League retained its London Steelyard and trading bases in Boston and Lynn. Memling's Last Judgement was never returned to its commissioner — it remains in Gdańsk to this day.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Paul Beneke became a civic hero — captain of a ship literally named <em>Peter von Danzig</em>. The seized Last Judgement triptych, displayed in the Basilica of the Assumption for centuries as the high altarpiece, is now the centrepiece of Gdańsk's National Museum — one of the greatest medieval artworks in Poland, and a permanent trophy of Hanseatic privateering.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Anglo-Hanseatic_War" target="_blank" rel="noopener">📖 Wikipedia — Anglo-Hanseatic War</a>`},
  // ── Polish-Teutonic War (1519–1521) ─────────────────────────
  // Corrected: previously mislabelled "War of the Priests" — that name
  // belongs to the earlier 1467–79 conflict (Pfaffenkrieg) above.
  // This war is known in German as the Reiterkrieg ("Rider's War").
  // Source: https://en.wikipedia.org/wiki/Polish%E2%80%93Teutonic_War_(1519%E2%80%931521)
  {start:1519, end:1521,  label:'Polish-Teutonic War (1519–1521)',       color:'#8b3a2a', detail:`<div class="war-also-known">Also known as: <strong>Reiterkrieg</strong> (German: "Rider's War") · <em>Wojna pruska</em> (Polish: "Prussian War")</div><div style="margin-bottom:10px;">The final military conflict between the Kingdom of Poland and the Teutonic Order. Grand Master Albert of Hohenzollern refused to pay the obligatory homage to Poland as required by the Second Peace of Toruń, allied with Muscovy (1517), and launched a war he hoped would recover Royal Prussia. The Polish Sejm declared war in December 1519. <em>Not to be confused with the War of the Priests (1467–79), an earlier ecclesiastical dispute about the Warmia bishopric.</em></div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland + Gdańsk (victor)</div><div class="war-side-name">Sigismund I "the Old"<br>Royal Prussian cities</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Grand Master Albert<br>of Hohenzollern-<br>Brandenburg-Ansbach</div></div></div><ul class="war-facts"><li><strong>Dec 1519</strong> — Polish forces invade Pomesania; Albert's Muscovite alliance fails to materialise effectively.</li><li><strong>Summer 1520</strong> — Teutonic forces strike Masovia and Warmia; briefly seize Tczew and Starogard Gdański.</li><li><strong>Aug 1520</strong> — Teutonic forces <strong>besiege Gdańsk</strong>; the city holds out. The Order retreats as Polish relief arrives and Teutonic funds collapse.</li><li><strong>5 Apr 1521</strong> — Compromise of Thorn: armistice signed; both sides exhausted.</li><li><strong>1523</strong> — Albert visits Wittenberg, meets Martin Luther, converts to Lutheranism.</li><li><strong>10 Apr 1525</strong> — Treaty of Kraków: Albert secularises the Order's territory as the <strong>Duchy of Prussia</strong> (Protestant, Polish fief); pays homage to Sigismund I in Kraków.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Decisive Polish Victory</div><div class="war-outcome-text">The Teutonic Order's Prussian state dissolved. The Duchy of Prussia became a Polish vassal — ending 217 years of Teutonic territorial power in the eastern Baltic.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk fought on the Polish side and successfully withstood the 1520 Teutonic siege. The 1525 dissolution of the Teutonic state permanently ended the Order's centuries-long threat to Royal Prussia, inaugurating Gdańsk's greatest era of commercial expansion as the Baltic's leading grain port.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Polish%E2%80%93Teutonic_War_(1519%E2%80%931521)" target="_blank" rel="noopener">📖 Wikipedia — Polish-Teutonic War (1519–1521)</a>`},
  {start:1563, end:1570,  label:'Livonian War (Sigismund II phase)',    color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Wojna inflancka</strong> (Polish) · <em>Ливонская война</em> (Russian) · First Northern War</div><div style="margin-bottom:10px;">A multi-power struggle for control of Livonia (modern Latvia and Estonia) — strategically vital for Baltic trade. After Ivan IV the Terrible invaded and nearly conquered Livonia, Poland-Lithuania entered the war to prevent Muscovite access to the Baltic Sea. Gdańsk's entire commercial prosperity depended on keeping Russian forces away from Baltic ports.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland-Lithuania (victor)</div><div class="war-side-name">Sigismund II Augustus<br>Stefan Báthory · Jan Zamoyski</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Ivan IV "the Terrible"<br>Tsardom of Russia</div></div></div><ul class="war-facts"><li><strong>22 Jan 1558</strong> — Ivan IV invades Livonia; captures Narva and Dorpat within months.</li><li><strong>1561</strong> — Livonian Confederation dissolves; Poland-Lithuania accepts Livonian submission.</li><li><strong>1576</strong> — Stefan Báthory becomes king; launches counter-offensive after settling the Danzig rebellion (1577).</li><li><strong>1579</strong> — Báthory recaptures Polotsk from Russia.</li><li><strong>1580–81</strong> — Báthory takes Velikie Luki; besieges Pskov but fails to take it.</li><li><strong>15 Jan 1582</strong> — Truce of Yam-Zapolsky: Russia surrenders all Livonian holdings to Poland.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Polish-Lithuanian Victory</div><div class="war-outcome-text">Truce of Yam-Zapolsky (15 January 1582). Russia surrendered all its Livonian and Polotsk holdings. Ivan IV's bid for Baltic Sea access failed, protecting the eastern Baltic trade network for decades.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk's entire commercial model depended on keeping Russian forces away from the Baltic coast. The city heavily financed the Polish war effort. In exchange, Sigismund II had already granted Gdańsk the 1557 Religious Freedom Privilege — effectively legalising the Lutheran Reformation — as reward for the city's financial and political loyalty. Báthory could not begin his decisive Livonian campaign until after he settled the Danzig rebellion in December 1577.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Livonian_War" target="_blank" rel="noopener">📖 Wikipedia — Livonian War</a>`},
  {start:1577, end:1577,  label:'Gdańsk Rebellion vs. Batory',         color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Bunt gdański</strong> (Polish, "Gdańsk Rebellion") · <em>Danziger Aufstand</em> (German) · Siege of Danzig (1577)</div><div style="margin-bottom:10px;">When Stefan Báthory was elected King of Poland in 1576, Gdańsk — fearing for its extraordinary autonomy — refused to recognise him and backed the Habsburg rival instead. Báthory responded with a trade blockade, then military force. Though his cavalry routed Gdańsk's army in the field, the city's walls held firm and the king eventually withdrew. Both sides claimed partial victory.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland (field victory)</div><div class="war-side-name">King Stefan Báthory<br>Jan Zborowski (field commander)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Gdańsk (political survival)</div><div class="war-side-name">Jan Winkelbruch (mercenary commander)<br>City militia + Scottish regiment</div></div></div><ul class="war-facts"><li><strong>1576</strong> — Gdańsk refuses Báthory's election; backs Habsburg Emperor Maximilian II instead.</li><li><strong>Jan 1577</strong> — Báthory captures Tczew; Gdańsk cut off from the hinterland by land.</li><li><strong>17 Apr 1577</strong> — Battle of Lubieszów: Zborowski's cavalry routs Gdańsk's army; over half are killed or captured.</li><li><strong>May–Sep 1577</strong> — Báthory besieges the city; Gdańsk sorties destroy significant Polish artillery.</li><li><strong>Sep 1577</strong> — Báthory withdraws, unable to breach the walls.</li><li><strong>Dec 1577</strong> — Settlement: Gdańsk pays 200,000 złoty; Báthory confirmed as king; all city privileges and Protestant rights explicitly reaffirmed.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Compromise settlement</div><div class="war-outcome-text">Settlement of December 1577. Gdańsk paid 200,000 złoty and acknowledged Báthory — but all trading privileges and Protestant rights were confirmed. The city's core autonomy survived intact.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Despite losing the field battle, Gdańsk won the political contest — its massive fortifications proved that even a Polish king could not take the city by force. The episode confirmed Gdańsk as effectively impregnable. Báthory later commissioned the Royal Chapel (built 1678–1681 under Sobieski) as a Catholic foothold next to Lutheran St. Mary's — a lasting symbol of the Crown's compromised but enduring relationship with the city.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Danzig_rebellion" target="_blank" rel="noopener">📖 Wikipedia — Danzig rebellion (1576–1577)</a>`},
  {start:1600, end:1629,  label:'Polish-Swedish Wars',                  color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Wojny polsko-szwedzkie</strong> (Polish) · Vasa Wars · Swedish-Polish Wars</div><div style="margin-bottom:10px;">Three decades of intermittent war between the Polish and Swedish branches of the Vasa dynasty, fought over Livonia, the Swedish throne, and Baltic commercial supremacy. Gustavus Adolphus's 1626 invasion of Royal Prussia brought Swedish forces to Gdańsk's doorstep. The city survived unoccupied, but was blockaded and financially bled by the peace terms.</div><div class="war-combatants"><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Sweden (gains territory + tolls)</div><div class="war-side-name">King Gustavus Adolphus<br>(Gustav II Adolf)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland-Lithuania</div><div class="war-side-name">Sigismund III Vasa<br>Hetman Stanisław Koniecpolski</div></div></div><ul class="war-facts"><li><strong>1600</strong> — War begins in Livonia; Polish-Swedish Vasa rivalry over the Swedish crown.</li><li><strong>1621</strong> — Gustavus Adolphus captures Riga; Sweden dominates eastern Livonia.</li><li><strong>Jun 1626</strong> — Gustavus Adolphus lands in Royal Prussia; 16 towns fall within weeks; Gdańsk harbour blockaded.</li><li><strong>Aug 1626</strong> — Battle of Dirschau (Tczew): Gustavus Adolphus wounded; inconclusive.</li><li><strong>28 Nov 1627</strong> — Battle of Oliwa (naval): Polish fleet defeats Swedish squadron in Gdańsk Bay — Poland's only significant naval victory of the wars.</li><li><strong>26 Sep 1629</strong> — Truce of Altmark: Sweden keeps most occupied Prussian ports; extracts two-thirds of all Gdańsk shipping tolls for six years.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Swedish strategic advantage</div><div class="war-outcome-text">Truce of Altmark (26 September 1629). Sweden retained occupied Prussian ports and extracted enormous toll revenues from Gdańsk's trade. The 1635 Truce of Stuhmsdorf returned most ports to Poland, but Gustavus Adolphus used the Altmark tolls to fund Sweden's entry into the Thirty Years' War.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk survived direct occupation but paid a heavy price: the Altmark treaty handed two-thirds of all port toll revenues to Sweden for six years, effectively taxing Gdańsk's trade to finance a foreign war. The Swedish blockade of surrounding ports devastated commerce. The 1627 naval battle of Oliwa, fought in the bay visible from the city, became a rare source of civic pride. Gdańsk's merchant class never fully recovered its earlier dominance of Baltic trade.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Polish%E2%80%93Swedish_wars" target="_blank" rel="noopener">📖 Wikipedia — Polish-Swedish Wars</a>`},
  {start:1655, end:1660,  label:'The Deluge (Swedish invasions)',       color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Potop szwedzki</strong> (Polish, "Swedish Deluge") · Second Northern War · <em>Karl X Gustavs polska krig</em> (Swedish)</div><div style="margin-bottom:10px;">The most catastrophic war in the Polish-Lithuanian Commonwealth's history. Two Swedish armies invaded simultaneously; within months Stockholm held Warsaw, Kraków, and most of Poland. Gdańsk stood as one of the last unconquered cities — and its defiance helped turn the tide. The Peace of Oliwa ending the war was signed literally within Gdańsk's territory.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Poland-Lithuania (ultimate victor)</div><div class="war-side-name">King John II Casimir<br>Stefan Czarniecki (resistance)<br>+ Dutch Republic (naval)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">King Charles X Gustav<br>Sweden<br>(+ Brandenburg, briefly)</div></div></div><ul class="war-facts"><li><strong>Jul–Aug 1655</strong> — Swedish forces invade from north and west; Polish armies collapse; most nobility surrenders at Ujście.</li><li><strong>Nov–Dec 1655</strong> — All of Royal Prussia falls to Sweden except <strong>Gdańsk</strong>, Puck, and Malbork.</li><li><strong>1655–1660</strong> — Gdańsk never surrenders; shelters the Polish royal treasury and archives; lends ~3 million złoty to the Crown; Dutch fleet helps break Swedish blockade.</li><li><strong>18 Nov 1655</strong> — Jasna Góra monastery successfully defends itself; galvanises national resistance.</li><li><strong>1657</strong> — Brandenburg switches sides (Treaty of Wehlau); coalition pushes Sweden back.</li><li><strong>3 May 1660</strong> — Peace of Oliwa signed at the Cistercian monastery in Oliwa — within Gdańsk's own territory.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Polish-Lithuanian recovery</div><div class="war-outcome-text">Peace of Oliwa (3 May 1660), signed at Oliwa monastery, Gdańsk. Sweden retained Livonia and Estonia; Brandenburg gained sovereignty over Ducal Prussia. Poland recovered most occupied territories. The Commonwealth survived — but never regained its former military power.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">One of very few Polish cities never to surrender during the Deluge. King John II Casimir sheltered in Gdańsk while Swedish forces occupied the surrounding region. The city lent vast sums to the Crown, maintained its garrison throughout, and hosted the Dutch naval support that helped break the Swedish blockade. In recognition, John Casimir granted additional trading privileges. The Peace of Oliwa was deliberately signed near Gdańsk to honour the city's extraordinary loyalty.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Deluge_(history)" target="_blank" rel="noopener">📖 Wikipedia — The Deluge (Potop)</a>`},
  {year:1677, start:1677, end:1678, label:'Prussian-Swedish siege attempt', color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Skånska kriget</strong> (Swedish, "Scanian War") · <em>Schwedisch-Brandenburgischer Krieg</em> (German)</div><div style="margin-bottom:10px;">A peripheral episode of the Scanian War (1675–1679), in which France backed Sweden against Brandenburg-Prussia, Denmark, and the Holy Roman Empire. As the "Great Elector" Frederick William swept through Swedish Pomerania, his forces briefly advanced toward Gdańsk's northern approaches — only to be reversed when France pressured Prussia to return all its Swedish conquests.</div><div class="war-combatants"><div class="war-side" style="background:rgba(60,60,80,0.12);border-left:3px solid rgba(60,60,80,0.5);"><div class="war-side-label">Brandenburg-Prussia</div><div class="war-side-name">Frederick William I<br>"the Great Elector"</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Sweden (backed by France)</div><div class="war-side-name">King Charles XI<br>Marshal Wrangel</div></div></div><ul class="war-facts"><li><strong>28 Jun 1675</strong> — Battle of Fehrbellin: Brandenburg defeats Sweden — the first such defeat in living memory.</li><li><strong>1677–78</strong> — Prussian forces campaign through Swedish Pomerania; Stettin, Stralsund, and Greifswald all fall; forces approach Gdańsk's northern approaches.</li><li><strong>4 Aug 1677</strong> — Brandenburg concludes a defensive alliance with Polish King John III Sobieski.</li><li><strong>Gdańsk fortifications intact</strong> — no direct assault ever attempted.</li><li><strong>29 Jun 1679</strong> — Treaty of Saint-Germain-en-Laye: France compels Brandenburg to return all Swedish Pomeranian conquests.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Status quo restored</div><div class="war-outcome-text">Treaty of Saint-Germain-en-Laye (1679). France forced Brandenburg-Prussia to return all Swedish Pomeranian conquests. Brandenburg received 300,000 talers as consolation — a bitter humiliation for Frederick William despite his battlefield victories.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The episode passed without direct military action against Gdańsk. The city's elaborate fortification network — the Bastion of St. Elizabeth, the Salvator fort, and the outer bastions — deterred any serious assault. The same walls that had held off Báthory in 1577 and survived the Swedish Deluge of 1655–60 remained Central Europe's most formidable urban defences.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Scanian_War" target="_blank" rel="noopener">📖 Wikipedia — Scanian War</a>`},
  {start:1700, end:1721,  label:'Great Northern War',                   color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Wielka Wojna Północna</strong> (Polish) · <em>Stora nordiska kriget</em> (Swedish) · Nordic War</div><div style="margin-bottom:10px;">A contest for Baltic dominance between Sweden — then the regional superpower — and a coalition led by Peter the Great's Russia. Sweden's military genius Charles XII won astonishing early victories but was annihilated at Poltava in 1709. Gdańsk paid for the war not with its walls but with half its population: a devastating plague carried by retreating armies killed more people than any siege in the city's history.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Coalition (victor)</div><div class="war-side-name">Peter the Great (Russia)<br>Augustus II (Poland-Saxony)<br>Frederick IV (Denmark)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">King Charles XII<br>Sweden</div></div></div><ul class="war-facts"><li><strong>Nov 1700</strong> — Battle of Narva: Charles XII's 8,000 men destroy a Russian army of 23,000.</li><li><strong>1706</strong> — Charles XII deposes Augustus II; installs Stanisław Leszczyński as puppet king of Poland.</li><li><strong>Mar 1709</strong> — Plague appears in Gdańsk; city council initially downplays it to protect trade — a fatal mistake.</li><li><strong>28 Jun 1709</strong> — Battle of Poltava: Russia crushes Sweden; Charles XII escapes to Ottoman Empire.</li><li><strong>1709–10</strong> — Plague kills an estimated 24,000–32,000 people in Gdańsk — approximately <strong>half the population</strong>.</li><li><strong>1710–11</strong> — Russian troops occupy Gdańsk's suburbs; city pays tribute.</li><li><strong>11 Sep 1721</strong> — Treaty of Nystad: Russia gains Estonia, Livonia, Ingria; Sweden's Baltic empire ends.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Russian ascendancy</div><div class="war-outcome-text">Treaty of Nystad (11 September 1721). Sweden lost its Baltic empire. Russia emerged as the dominant Baltic power and Peter I assumed the title Emperor. For Gdańsk, the war's legacy was catastrophic demographic and commercial collapse.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The 1709–10 plague — not swords but retreating soldiers — killed approximately half the city's population in twelve months, the deadliest event in Gdańsk's history. Russian troops occupied the suburbs and extorted tribute. Trade collapsed entirely. Gdańsk's population and commercial dominance never fully recovered; the Great Northern War marked the beginning of the city's long decline from the Baltic's leading entrepôt to a provincial port.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Great_Northern_War" target="_blank" rel="noopener">📖 Wikipedia — Great Northern War</a>`},
  {start:1733, end:1735,  label:'War of Polish Succession — siege 1734', color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Oblężenie Gdańska (1734)</strong> (Polish) · <em>Belagerung von Danzig</em> (German) · Siege of Danzig 1734</div><div style="margin-bottom:10px;">A European dynastic conflict triggered by the death of Augustus II of Poland. France backed Louis XV's father-in-law Stanisław Leszczyński; Russia and Austria backed Saxon Prince Augustus III. Leszczyński fled to Gdańsk, transforming the city into the theatre of the war's principal military action. The resulting 135-day siege was the most financially destructive in Gdańsk's history.</div><div class="war-combatants"><div class="war-side" style="background:rgba(60,60,80,0.12);border-left:3px solid rgba(60,60,80,0.5);"><div class="war-side-label">Russia + Saxony (victor)</div><div class="war-side-name">Field Marshal von Münnich<br>Admiral Thomas Gordon</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Gdańsk + France</div><div class="war-side-name">General von Bittinghofen (city governor)<br>French fleet (3 ships, 2,400 troops)</div></div></div><ul class="war-facts"><li><strong>Oct 1733</strong> — Leszczyński elected king; Russia invades within weeks; he flees to Gdańsk.</li><li><strong>22 Feb 1734</strong> — Russian-Saxon forces encircle Gdańsk; formal siege begins.</li><li><strong>17 Mar 1734</strong> — Field Marshal von Münnich arrives with 15,000 reinforcements; ~60,000 total besiegers.</li><li><strong>May 1734</strong> — French relief fleet lands 2,400 troops at <strong>Westerplatte</strong>; attempt to storm Russian lines fails; French fleet surrenders on 1 June.</li><li><strong>28 Jun 1734</strong> — Leszczyński escapes the city disguised as a peasant — two days before surrender.</li><li><strong>30 Jun 1734</strong> — Gdańsk capitulates unconditionally after 135 days; Russian artillery had bombarded church towers throughout.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Russian-Saxon Victory</div><div class="war-outcome-text">Treaty of Vienna (1738). Augustus III confirmed as King of Poland. Leszczyński received the Duchy of Lorraine as consolation (reverting to France on his death in 1766). Gdańsk surrendered unconditionally.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The most financially catastrophic siege in Gdańsk's history. Russian artillery bombarded church towers; St. Mary's nave cracked. The forced indemnity of 2 million thalers crippled municipal finances for generations. Remarkably, the French troops landed their relief force at Westerplatte — the same peninsula where the Second World War would begin in 1939. The siege also marked the first time French and Russian troops fought each other in battle.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Siege_of_Danzig_(1734)" target="_blank" rel="noopener">📖 Wikipedia — Siege of Danzig (1734)</a>`},
  {start:1806, end:1807,  label:'War of 4th Coalition — French siege',  color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Siège de Dantzig</strong> (French) · <em>Belagerung von Danzig (1807)</em> (German) · Part of the War of the Fourth Coalition</div><div style="margin-bottom:10px;">As Napoleon's Grande Armée swept through Prussia after Jena-Auerstedt (1806), Gdańsk — then a Prussian fortress city — became a strategic prize. Marshal Lefebvre commanded a mixed force of French, Polish, and Saxon troops. After a 65-day siege and a failed Russian naval relief attempt, the Prussian garrison surrendered and Napoleon created the short-lived Free City of Danzig.</div><div class="war-combatants"><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">France + allies (victor)</div><div class="war-side-name">Marshal François Lefebvre<br>Gen. Dąbrowski (Polish division)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Prussia + Russia</div><div class="war-side-name">General Count Kalckreuth<br>(14,400 Prussian defenders)</div></div></div><ul class="war-facts"><li><strong>19 Mar 1807</strong> — French siege begins; 27,000 troops encircle 14,400 Prussian defenders.</li><li><strong>23 Mar 1807</strong> — French artillery bombardment commences; church towers damaged.</li><li><strong>10–15 May 1807</strong> — Russian naval relief attempt: 8,000 men on 57 transports, escorted by a British sloop and Swedish warship — repulsed by French lines.</li><li><strong>21 May 1807</strong> — French storm Hagelsberg (Góra Gradowa), the key commanding height above the city.</li><li><strong>24 May 1807</strong> — Gdańsk surrenders; Prussian garrison marches out with full military honours of war.</li><li><strong>28 May 1807</strong> — Napoleon creates the Napoleonic Free City of Danzig; Lefebvre made Duke of Danzig.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — French victory</div><div class="war-outcome-text">Gdańsk capitulated 24 May 1807. Napoleon established the Napoleonic Free City of Danzig (1807–1814) as a semi-independent French satellite state. The freed besieging forces contributed to the French victory at Friedland (14 June 1807) and the Treaty of Tilsit.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Multiple churches were converted to military use during the occupation: St. Elizabeth's and parts of St. Bridget's became warehouses; others served as hospitals and barracks. The 65-day bombardment damaged church towers. Under French occupation, the Jewish community received civil rights for the first time in Gdańsk's history. The Napoleonic Free City (1807–1814) gave Gdańsk a brief experiment in French-style governance before the Russian siege of 1813 ended it.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Siege_of_Danzig_(1807)" target="_blank" rel="noopener">📖 Wikipedia — Siege of Danzig (1807)</a>`},
  {start:1812, end:1814,  label:'Napoleonic collapse — Russian siege',  color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Belagerung von Danzig (1813–14)</strong> (German) · Second Siege of Danzig · Longest siege in Gdańsk's history (354 days)</div><div style="margin-bottom:10px;">After Napoleon's catastrophic Russian campaign, retreating Grande Armée troops swelled Gdańsk's garrison to enormous size. Governor-General Jean Rapp was ordered to hold the city at all costs. The resulting 354-day siege — the longest in Gdańsk's history — reduced a force of 30,000 to barely 10,000 survivors through starvation and epidemic disease.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Russia + Prussia (victor)</div><div class="war-side-name">Duke Alexander of Württemberg<br>(~40,000 besieging forces)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">France (garrison)</div><div class="war-side-name">General Jean Rapp<br>(~30,000 nominal; ~10,000 fit)</div></div></div><ul class="war-facts"><li><strong>16 Jan 1813</strong> — Russian-Prussian forces begin encirclement of Gdańsk.</li><li><strong>Mar 1813</strong> — Russians divert the Radaune canal; city loses its water supply. Up to 150 people dying per day from typhoid and starvation.</li><li><strong>Apr 1813</strong> — Duke Alexander of Württemberg takes overall command of besieging forces.</li><li><strong>2 Nov 1813</strong> — Great fire on the Speicherinsel (Granary Island): 173 warehouses destroyed; 2 million Thaler in losses — the city's entire commercial infrastructure.</li><li><strong>Oct 1813</strong> — Battle of Leipzig: Napoleon decisively defeated; all hope of relief for Gdańsk ends.</li><li><strong>2 Jan 1814</strong> — Rapp surrenders; ~10,000 survivors march out as prisoners of war (over 20,000 died in the siege).</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Allied victory</div><div class="war-outcome-text">French surrender, 2 January 1814. Gdańsk was returned to Prussia at the Congress of Vienna (1815), ending the short-lived Napoleonic Free City. Rapp went into captivity; he was released after Napoleon's abdication in April 1814.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The longest siege in the city's history (354 days). Every church nave served as a hospital; the vaulted medieval interiors sheltered thousands of dying soldiers and civilians. The fire on the Speicherinsel (the iconic Granary Island) destroyed 173 warehouses and obliterated the city's commercial infrastructure. The civilian population suffered acute starvation for nearly a full year. The siege left Gdańsk economically prostrated and its population drastically reduced.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Siege_of_Danzig_(1813)" target="_blank" rel="noopener">📖 Wikipedia — Siege of Danzig (1813–14)</a>`},
  {start:1870, end:1871,  label:'Franco-Prussian War',                  color:'#705030', detail:`<div class="war-also-known">Also known as: <strong>Deutsch-Französischer Krieg</strong> (German) · <em>Guerre franco-prussienne</em> (French) · Franco-German War</div><div style="margin-bottom:10px;">Bismarck's decisive war against France that forged the German Empire. Gdańsk saw no fighting, but the war transformed the political world in which the city lived — absorbing it into a new, assertively nationalist German Empire and inaugurating Bismarck's Kulturkampf, which systematically suppressed Polish culture and language across Prussian Poland.</div><div class="war-combatants"><div class="war-side" style="background:rgba(60,60,80,0.12);border-left:3px solid rgba(60,60,80,0.5);"><div class="war-side-label">North German Confederation (victor)</div><div class="war-side-name">King Wilhelm I · Bismarck<br>Field Marshal von Moltke</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Against</div><div class="war-side-name">Emperor Napoleon III<br>French Second Empire</div></div></div><ul class="war-facts"><li><strong>19 Jul 1870</strong> — France declares war; German states rally behind Prussia; 380,000 troops reach the frontier within 18 days.</li><li><strong>1–2 Sep 1870</strong> — Battle of Sedan: Napoleon III captured with 104,000 men — the decisive blow.</li><li><strong>18 Jan 1871</strong> — German Empire proclaimed in the Hall of Mirrors at Versailles — German unification achieved.</li><li><strong>10 May 1871</strong> — Treaty of Frankfurt: France cedes Alsace-Lorraine; pays 5 billion gold francs.</li><li><strong>1871–78</strong> — Bismarck launches Kulturkampf: Polish-language instruction banned in Prussian schools, Catholic institutions suppressed.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — German Empire born</div><div class="war-outcome-text">Treaty of Frankfurt (10 May 1871). France ceded Alsace-Lorraine and paid 5 billion francs. The German Empire was proclaimed at Versailles — the most powerful state in Europe. Gdańsk became a city of the new Reich.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">No fighting reached Gdańsk — the city contributed logistically, with Prussian regiments from the Danzig garrison mobilised and sent west. German unification incorporated Gdańsk into the new German Empire. Bismarck's Kulturkampf (1871–78) then targeted the city's Polish-speaking minority: Polish-language instruction was banned, Catholic institutions suppressed, and systematic Germanisation began that would shape the city's demographics until 1919.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Franco-Prussian_War" target="_blank" rel="noopener">📖 Wikipedia — Franco-Prussian War</a>`},
  {start:1914, end:1918,  label:'World War I',                          color:'#a04040', detail:`<div class="war-also-known">Also known as: <strong>Der Erste Weltkrieg</strong> (German) · The Great War · <em>Wielka Wojna</em> (Polish)</div><div style="margin-bottom:10px;">The first industrial-scale global conflict, triggered by the assassination of Archduke Franz Ferdinand and ignited by a web of alliances. Gdańsk served as an important German naval base and supply hub throughout. Its outcome — Germany's defeat and the punitive Treaty of Versailles — severed Gdańsk from Germany as the Free City of Danzig, creating the "Danzig Question" that would help ignite the next war twenty years later.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Allied Powers (victor)</div><div class="war-side-name">France · Britain + Empire<br>Russia · Italy · USA (1917)</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Central Powers</div><div class="war-side-name">Germany · Austria-Hungary<br>Ottoman Empire · Bulgaria</div></div></div><ul class="war-facts"><li><strong>28 Jun 1914</strong> — Archduke Franz Ferdinand assassinated in Sarajevo; alliance chain activated.</li><li><strong>Aug 1914</strong> — Germany invades Belgium and France; war engulfs Europe.</li><li><strong>1914–18</strong> — Gdańsk serves as key German Baltic naval base: U-boat tenders, troop transports, and Eastern Front supply depots operate from the port.</li><li><strong>Nov 1917</strong> — Russian Revolution collapses the Eastern Front; USA enters on the Allied side.</li><li><strong>11 Nov 1918</strong> — Armistice; Germany defeated and humiliated.</li><li><strong>28 Jun 1919</strong> — Treaty of Versailles: Germany loses 13% of its territory; Gdańsk separated as the Free City of Danzig under League of Nations protection.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Allied victory</div><div class="war-outcome-text">Treaty of Versailles (28 June 1919). Germany stripped of territory, colonies, and military capacity. Gdańsk separated as the Free City of Danzig — neither German nor Polish — under League of Nations supervision. Poland received the "Polish Corridor," cutting Germany in two.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">Gdańsk served as a major German naval and supply base throughout the war. The Versailles settlement separating the city from Germany generated intense resentment among its predominantly German population. The "Danzig Question" — whether the city should return to Germany — became one of the central grievances that Nazi propaganda exploited as the stated pretext for invading Poland in September 1939. The unresolved status of Gdańsk from 1920 to 1939 made it the symbolic flashpoint of the coming world war.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Free_City_of_Danzig" target="_blank" rel="noopener">📖 Wikipedia — Free City of Danzig</a>`},
  {start:1939, end:1945,  label:'World War II',                         color:'#c03030', detail:`<div class="war-also-known">Also known as: <strong>Zweiter Weltkrieg</strong> (German) · Second World War · Battle of Danzig (1945)</div><div style="margin-bottom:10px;">The war began here — at Gdańsk. At 4:47 AM on 1 September 1939, the German battleship <em>Schleswig-Holstein</em> opened fire on the Polish transit depot at Westerplatte, firing the opening shots of the Second World War. Six years later, Soviet forces and fires destroyed 90% of the historic city that had stood for centuries. What survived was a ruin — and what rose from it was a deliberate act of cultural reconstruction.</div><div class="war-combatants"><div class="war-side" style="background:rgba(140,58,42,0.12);border-left:3px solid rgba(140,58,42,0.5);"><div class="war-side-label">Allied Powers (victor)</div><div class="war-side-name">Soviet Union (Marshal Rokossovsky)<br>Polish 1st Warsaw Armoured Brigade</div></div><div class="war-vs">⚔</div><div class="war-side" style="background:rgba(80,80,80,0.10);border-left:3px solid rgba(120,120,120,0.4);"><div class="war-side-label">Nazi Germany</div><div class="war-side-name">General Dietrich von Saucken<br>German 2nd Army (defence)</div></div></div><ul class="war-facts"><li><strong>1 Sep 1939, 4:47 AM</strong> — <em>Schleswig-Holstein</em> opens fire on Westerplatte. WWII begins.</li><li><strong>1–7 Sep 1939</strong> — 182 Polish soldiers under Major Henryk Sucharski hold Westerplatte for 7 days against ~3,500 Germans — a symbol of resistance celebrated to this day.</li><li><strong>19 Sep 1939</strong> — Gdańsk formally annexed to the Reich as "Danzig-Westpreußen."</li><li><strong>1939–45</strong> — City serves as a major German naval shipyard; submarines built and repaired; tens of thousands of forced labourers brought in.</li><li><strong>15–30 Mar 1945</strong> — Soviet 2nd Belorussian Front attacks; savage street fighting; fires spread through the historic centre.</li><li><strong>28 Mar 1945</strong> — Polish flag raised at the Artus Court by soldiers of the Polish 1st Warsaw Armoured Brigade.</li><li><strong>30 Mar 1945</strong> — Danzig falls; 90–95% of the historic core destroyed.</li></ul><div class="war-outcome"><div class="war-outcome-label">Outcome — Allied victory</div><div class="war-outcome-text">Germany unconditionally surrendered (8 May 1945). Gdańsk returned to Poland. The German population (170,000+) fled or was expelled. The city was resettled by Poles — largely from Lwów and central Poland. Reconstruction of the historic core began in the 1950s as a deliberate act of cultural reclamation.</div></div><div class="war-gdansk"><div class="war-gdansk-label">Gdańsk</div><div class="war-gdansk-text">The Westerplatte garrison's seven-day stand became the defining symbol of Polish defiance — immortalised in film, literature, and national memory. The Soviet assault and subsequent fires gutted every major historic church: St. Mary's, St. Catherine's, St. Nicholas', St. Bridget's and the rest were burned-out shells. Polish craftsmen then spent decades meticulously reconstructing the interiors from historical records, photographs, and surviving fragments. The rebuilt churches — stone by stone identical to the originals — are monuments both to the destruction of 1945 and to the extraordinary will to restore what was lost.</div></div><a class="war-wiki-link" href="https://en.wikipedia.org/wiki/Siege_of_Danzig_(1945)" target="_blank" rel="noopener">📖 Wikipedia — Battle of Danzig (1945)</a>`},
];

